package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/mux"
)

type Comment struct {
	ID    string `json:"id"`
	Text  string `json:"text"`
	User  string `json:"user"`
	Tags  []string `json:"tags"`
	Links []string `json:"links"`
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id := vars["id"]

	comments := []Comment{
		{ID: "1", Text: "<b>Hello</b> <i>World!</i>", User: "John Doe", Tags: []string{"tag1", "tag2"}, Links: []string{"https://example.com"}},
		{ID: "2", Text: "This is a comment with <a href='https://example.com'>link</a>", User: "Jane Doe", Tags: []string{"tag3", "tag4"}, Links: []string{}},
	}

	template := `
	<html>
	<head>
		<title>Comments</title>
	</head>
	<body>
		<h1>Comments for {{.ID}}</h1>
		<ul>
			{{range .Comments}}
				<li>
					<b>{{.User}}:</b> {{.Text | safeHTML}}
					<p>Tags: {{join .Tags ", "}}</p>
					<p>Links: {{join .Links ", "}}</p>
				</li>
			{{end}}
		</ul>
	</body>
	</html>
	`

	err := renderTemplate(w, template, map[string]interface{}{"ID": id, "Comments": comments})
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/comments/{id}", commentsHandler).Methods("GET")

	fmt.Println("Server is listening on port 8080")
	log.Fatal(http.ListenAndServe(":8080", r))
}

func renderTemplate(w http.ResponseWriter, template string, data map[string]interface{}) error {
	t, err := template.Parse(template)
	if err != nil {
		return err
	}
	return t.Execute(w, data)
}